const env = typeof $env !== 'undefined' ? $env : {};
const supabaseUrl = (env.SUPABASE_URL || process.env.SUPABASE_URL || '').replace(/\/$/, '');
const serviceRoleKey = env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_SERVICE_ROLE_KEY || '';

if (!supabaseUrl || !serviceRoleKey) {
  throw new Error('Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY in n8n environment.');
}

const restHeaders = {
  apikey: serviceRoleKey,
  Authorization: `Bearer ${serviceRoleKey}`,
  'Content-Type': 'application/json',
};

async function httpRequest(options) {
  return this.helpers.httpRequest({ json: true, ...options });
}

async function supabaseGet(path) {
  return httpRequest.call(this, { method: 'GET', url: `${supabaseUrl}/rest/v1/${path}`, headers: restHeaders });
}

async function supabasePost(path, body) {
  return httpRequest.call(this, {
    method: 'POST',
    url: `${supabaseUrl}/rest/v1/${path}`,
    headers: { ...restHeaders, Prefer: 'return=representation' },
    body,
  });
}

function enc(value) {
  return encodeURIComponent(String(value));
}

function utcDate(date = new Date()) {
  return date.toISOString().slice(0, 10);
}

function timeToMinutes(value) {
  const [hours = '0', minutes = '0'] = String(value || '00:00').split(':');
  return Number(hours) * 60 + Number(minutes);
}

function compactIds(rows, key = 'id', max = 20) {
  return (rows || []).map((row) => row[key]).filter(Boolean).slice(0, max);
}

const now = new Date();
const windowMinutes = 60;
const windowEnd = new Date(now.getTime() + windowMinutes * 60 * 1000);
const nowIso = now.toISOString();
const windowEndIso = windowEnd.toISOString();
const runStartedAt = nowIso;

const bookings = await supabaseGet(`bookings?select=id,coach_id,client_id,scheduled_at,duration_minutes,status&status=eq.confirmed&scheduled_at=gte.${enc(nowIso)}&scheduled_at=lte.${enc(windowEndIso)}&order=scheduled_at.asc&limit=1000`);
const coachProfiles = await supabaseGet('coach_profiles?select=id,user_id&user_id=not.is.null&limit=1000');
const coachUserByCoachId = new Map((coachProfiles || []).map((coach) => [coach.id, coach.user_id]));
const results = [];
const stats = {
  run_started_at: runStartedAt,
  window_start: nowIso,
  window_end: windowEndIso,
  window_minutes: windowMinutes,
  bookings_found: (bookings || []).length,
  created_count: 0,
  skipped_existing_notification_count: 0,
  skipped_missing_coach_user_count: 0,
  error_count: 0,
};

async function ensureReminder({ booking, userId, recipientRole }) {
  const existing = await supabaseGet(`notifications?select=id&user_id=eq.${userId}&data->>kind=eq.booking_starting_soon&data->>booking_id=eq.${booking.id}&data->>recipient_role=eq.${recipientRole}&data->>window_minutes=eq.${windowMinutes}&limit=1`);
  if (existing[0]?.id) return { id: existing[0].id, created: false };

  const body = recipientRole === 'coach'
    ? 'You have a confirmed coaching session starting soon.'
    : 'Your confirmed coaching session starts soon.';
  const inserted = await supabasePost('notifications', {
    user_id: userId,
    type: 'booking_reminder',
    title: 'Upcoming session',
    body,
    data: {
      kind: 'booking_starting_soon',
      booking_id: booking.id,
      recipient_role: recipientRole,
      coach_id: booking.coach_id,
      client_id: booking.client_id,
      scheduled_at: booking.scheduled_at,
      window_minutes: windowMinutes,
    },
  });

  const notification = inserted[0];
  if (!notification?.id) throw new Error('Supabase did not return inserted notification id.');
  return { id: notification.id, created: true };
}

for (const booking of bookings || []) {
  try {
    const coachUserId = coachUserByCoachId.get(booking.coach_id);
    if (!coachUserId) {
      stats.skipped_missing_coach_user_count += 1;
      results.push({ booking_id: booking.id, status: 'skipped_missing_coach_user' });
      continue;
    }

    for (const recipient of [
      { role: 'client', userId: booking.client_id },
      { role: 'coach', userId: coachUserId },
    ]) {
      const reminder = await ensureReminder({ booking, userId: recipient.userId, recipientRole: recipient.role });
      if (reminder.created) stats.created_count += 1;
      else stats.skipped_existing_notification_count += 1;
      results.push({ booking_id: booking.id, recipient_role: recipient.role, user_id: recipient.userId, status: reminder.created ? 'created' : 'skipped_existing_notification', notification_id: reminder.id });
    }
  } catch (error) {
    stats.error_count += 1;
    results.push({ booking_id: booking.id, status: 'error', error: error instanceof Error ? error.message : String(error) });
  }
}

return [
  { json: { type: 'summary', status: stats.error_count > 0 ? 'completed_with_errors' : 'completed', finished_at: new Date().toISOString(), ...stats } },
  ...results.map((result) => ({ json: { type: 'booking_result', ...result } })),
];
